<div class="en">
<svg viewBox="0 0 700 460" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Pakistan's Crypto Policy Timeline</text>
  <text x="20" y="50" fill="#71717a" font-size="13" font-family="sans-serif">Six Months Where Regulatory Infrastructure and Religious Ruling Collided</text>
